const body = $input.first().json.body || $input.first().json;
const tenantId = body.tenantId;
const automationId = body.automationId;

if (!tenantId || !automationId) {
  return [{ json: { success: false, error: 'tenantId et automationId requis' } }];
}

return [{ json: { tenantId, automationId, valid: true } }];

const purchase = $input.first().json;
const data = $('02. Preparer donnees').first().json;
const workflowIds = purchase.n8n_workflow_ids || [];
const baseUrl = $env.N8N_API_URL || 'http://localhost:5678';
const results = [];

for (const wfId of workflowIds) {
  try {
    const resp = await fetch(`${baseUrl}/api/v1/workflows/${wfId}/deactivate`, {
      method: 'POST',
      headers: { 'X-N8N-API-KEY': $env.N8N_API_KEY || '' }
    });
    results.push({ workflowId: wfId, success: resp.ok, status: resp.status });
  } catch (err) {
    results.push({ workflowId: wfId, success: false, error: String(err) });
  }
}

const successCount = results.filter(r => r.success).length;

return [{ json: {
  tenantId: data.tenantId,
  automationId: data.automationId,
  deactivated: successCount,
  total: workflowIds.length,
  results
} }];

const data = $('05. Desactiver workflows n8n').first().json;
return [{ json: {
  success: true,
  message: `Automatisation suspendue (${data.deactivated}/${data.total} workflows desactives)`
} }];
